package main

import (
	"fmt"
	"io"
	"net/http"
	"os"
)

func uploadFile(w http.ResponseWriter, r *http.Request) {
	r.ParseMultipartForm(10 << 20)
    file, handler, err := r.FormFile("myFile")
    if err != nil {
        fmt.Println("Error retrieving the file")
        fmt.Println(err)
        return
    }
	defer file.Close()

	fmt.Fprintf(w, "%v", handler.Header)

	//Create a file on server with unique name and copy from source to destination
	f, err := os.OpenFile("./public/"+handler.Filename, os.O_WRONLY|os.O_CREATE, 0666)
	if err != nil {
		fmt.Println(err)
		return
	}
	defer f.Close()

	_, err = io.Copy(f, file)
	if err != nil {
		fmt.Fprintf(w, "Error while copying the file")
		fmt.Fprintf(w, "%v", err)
		return
	}

	//Return the path of uploaded file 
    fmt.Fprintf(w, "\nFile Uploaded successfully. You can access it at: public/%s\n", handler.Filename)
}

func setupRoutes() {
	http.HandleFunc("/upload", uploadFile)
	http.ListenAndServe(":8080", nil)
}

func main() {
	fmt.Println("Go File Upload")
	setupRoutes()
}